<?php
/**
 * ALG3PL Scale Batch 1 — Deploy Script
 * Upload to public/ and hit via browser once; it self-deletes.
 */

if (php_sapi_name() === "cli") { die("Must run via HTTP.\n"); }

header("Content-Type: text/plain; charset=utf-8");

$files = [
    'app/Providers/AppServiceProvider.php'
        => '',
    'app/Filament/Widgets/LeadHeroWidget.php'
        => '',
    'app/Filament/Widgets/SmartAlertsWidget.php'
        => '',
    'app/Filament/Widgets/RegionalMapWidget.php'
        => '',
    'app/Filament/Widgets/SalesPipelineWidget.php'
        => '',
    'app/Filament/Pages/Dashboard.php'
        => '',
    'app/Jobs/ScoreLeadJob.php'
        => '',
    'app/Observers/LeadObserver.php'
        => '',
    'app/Providers/Filament/AdminPanelProvider.php'
        => '',
    'app/Http/Controllers/WebhookInboundController.php'
        => '',
];

$base   = dirname(__DIR__);
$errors = [];

foreach ($files as $rel => $b64) {
    $dest  = $base . '/' . $rel;
    $dir   = dirname($dest);

    if (!is_dir($dir) && !mkdir($dir, 0755, true)) {
        $errors[] = "FAIL mkdir: $dir";
        continue;
    }

    $bytes = base64_decode($b64, true);
    if ($bytes === false) {
        $errors[] = "FAIL base64_decode: $rel";
        continue;
    }

    if (file_put_contents($dest, $bytes) === false) {
        $errors[] = "FAIL write: $rel";
    } else {
        echo "OK: $rel\n";
    }
}

if (!empty($errors)) {
    echo "\n--- ERRORS ---\n";
    foreach ($errors as $e) { echo $e . "\n"; }
} else {
    echo "\nAll files written successfully.\n";
}

// Self-delete
@unlink(__FILE__);
echo "Deploy complete. Script self-deleted.\n";
